<script>
	export default {
		globalData: {

		},

		onLaunch: function() {
			console.log('App Launch');
			uni.getLocation({
				type: 'gcj02', // 返回国测局坐标，可用于 wx.openLocation
				success: (res) => {
					const {
						latitude,
						longitude
					} = res;
					this.getWeather(longitude, latitude);
				},
				fail: (err) => {
					console.error('获取位置失败：', err);
				}
			})
		},
		onShow: function() {
			console.log('App Show')
		},
		onHide: function() {
			console.log('App Hide')
		},
		methods: {
			async getWeather(lon, lat) {
				const key = 'd2885a769f0a4646b8c934f5fdef054f';
				uni.request({
					url: `https://nj3jpfq5xf.re.qweatherapi.com/geo/v2/city/lookup`,
					data: {
						key,
						location: `${lon},${lat}`
					},
					success: (res) => {
						const adcode = res.data;
						this.getWeatherByAdcode(adcode);
					}
				})
			}
			
		}
	}
</script>

<style>
	/*每个页面公共css */
	@import "@/common/style.css";
	@import "@/common/iconfont.css";
</style>